import Fondo from "../Cabañas/Foto9.jpg"

const Actividades = () => {
    return (
        <section className="h-screen snap-start flex items-center justify-center" style={{
                backgroundImage: `url('${Fondo}')`,
                backgroundAttachment: "fixed",
                backgroundSize: "cover",
                backgroundPosition: "center",
            }}
        >
            <div className="absolute inset-0 bg-black/50">
            <div className="relative z-10 text-center text-white p-6 rounded-lg">
                <h2 className="text-4xl font-playfair mb-4">Actividades</h2>
                <p className="text-lg font-roboto max-w-2xl mx-auto">
                    Disfrutá de una amplia variedad de actividades para toda la familia. Desde relajantes paseos por la naturaleza hasta emocionantes aventuras al aire libre, tenemos algo para cada gusto. Sumergite en la tranquilidad de nuestro entorno natural o explorá nuevas experiencias con nuestras actividades diseñadas para crear recuerdos inolvidables.
                </p>
                </div>
            </div>

            
        </section>
    );
}
export default Actividades;
